  let _intervalId = null;
  let _speedMultiplier = 1.0;
  let _currentFrame = 0;
  let _cycleCount = 0;
  let _maxCycles = Infinity;

  function dispatchFrame(frameData) {
    window.dispatchEvent(new CustomEvent('synthia:action', {
      detail: { jointOverrides: frameData.overrides }
    }));
    const rm = frameData.rootMotion;
    if (rm && (rm.dx !== 0 || rm.dz !== 0)) {
      const binder = window.__SYNTHIA_HUMANOID_BINDER__;
      const capsuleBody = binder && binder.getCapsuleBody && binder.getCapsuleBody();
      if (capsuleBody && capsuleBody.isValid()) {
        const t = capsuleBody.translation();
        capsuleBody.setTranslation({ x: t.x + rm.dx, y: t.y, z: t.z + rm.dz }, true);
      }
    }
  }

  function stepFrame() {
    const frame = WALK_ANIMATION[_currentFrame];
    dispatchFrame(frame);

    _currentFrame++;
    if (_currentFrame >= WALK_ANIMATION.length) {
      _currentFrame = 0;
      _cycleCount++;
      if (_cycleCount >= _maxCycles) {
        walkStop();
        console.log('[WALK] Completed ' + _maxCycles + ' cycle(s). Stopped.');
        return;
      }
    }
  }

  function walkStart(maxCycles) {
    walkStop();
    _currentFrame = 0;
    _cycleCount = 0;
    _maxCycles = maxCycles || Infinity;

    const baseInterval = 1000 / 30;
    const interval = Math.round(baseInterval / _speedMultiplier);

    console.log('[WALK] Starting walk cycle. Speed: ' + _speedMultiplier + 'x, Interval: ' + interval + 'ms per frame');
    _intervalId = setInterval(stepFrame, interval);
  }

  function walkStop() {
    if (_intervalId !== null) {
      clearInterval(_intervalId);
      _intervalId = null;
    }
    _currentFrame = 0;
    _cycleCount = 0;
    window.dispatchEvent(new CustomEvent('synthia:resetPose'));
    console.log('[WALK] Stopped. Pose reset.');
  }

  function walkSpeed(multiplier) {
    if (typeof multiplier !== 'number' || multiplier <= 0) {
      console.error('[WALK] Speed must be a positive number.');
      return;
    }
    _speedMultiplier = multiplier;
    if (_intervalId !== null) {
      const wasRunning = true;
      walkStop();
      if (wasRunning) walkStart(_maxCycles);
    }
    console.log('[WALK] Speed set to ' + _speedMultiplier + 'x');
  }

  function walkCycle(cycles) {
    walkStart(cycles);
  }

  window.walkStart = walkStart;
  window.walkStop = walkStop;
  window.walkSpeed = walkSpeed;
  window.walkCycle = walkCycle;
  window.WALK_ANIMATION = WALK_ANIMATION;

  console.log('═══════════════════════════════════════════════════════════');
  console.log('  Synthia Walking Simulation Loaded (with root motion)');
  console.log('  ' + WALK_ANIMATION.length + ' frames @ 30fps = ' + (WALK_ANIMATION.length / 30).toFixed(2) + 's per cycle');
  console.log('');
  console.log('  walkStart()      — begin walking (infinite loop)');
  console.log('  walkStop()       — stop & reset to rest pose');
  console.log('  walkSpeed(n)     — set speed (0.25 = quarter, 2 = double)');
  console.log('  walkCycle(n)     — walk for n cycles then stop');
  console.log('═══════════════════════════════════════════════════════════');

